import { useState, useMemo } from "react";
import {
  LineChart, Line, BarChart, Bar, PieChart, Pie, Cell,
  AreaChart, Area, RadarChart, Radar, PolarGrid, PolarAngleAxis,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from "recharts";

// ─── BASE DATASET (2024) ─────────────────────────────────────────────────────
const BASE_MONTHLY = [
  { month: "Jan", accidents: 312, deaths: 42, injuries: 198 },
  { month: "Feb", accidents: 278, deaths: 38, injuries: 176 },
  { month: "Mar", accidents: 345, deaths: 51, injuries: 224 },
  { month: "Apr", accidents: 389, deaths: 55, injuries: 261 },
  { month: "May", accidents: 421, deaths: 63, injuries: 289 },
  { month: "Jun", accidents: 458, deaths: 71, injuries: 312 },
  { month: "Jul", accidents: 502, deaths: 84, injuries: 341 },
  { month: "Aug", accidents: 487, deaths: 79, injuries: 328 },
  { month: "Sep", accidents: 443, deaths: 68, injuries: 298 },
  { month: "Oct", accidents: 398, deaths: 59, injuries: 271 },
  { month: "Nov", accidents: 356, deaths: 48, injuries: 234 },
  { month: "Dec", accidents: 411, deaths: 62, injuries: 287 },
];

const BASE_LOCATION = [
  { location: "Highway NH-8", accidents: 524, injuries: 342, deaths: 87 },
  { location: "City Center", accidents: 412, injuries: 289, deaths: 45 },
  { location: "Ring Road", accidents: 378, injuries: 241, deaths: 62 },
  { location: "Industrial Zone", accidents: 298, injuries: 198, deaths: 51 },
  { location: "Suburb North", accidents: 241, injuries: 167, deaths: 38 },
  { location: "Airport Road", accidents: 187, injuries: 124, deaths: 29 },
  { location: "Port Area", accidents: 156, injuries: 98, deaths: 24 },
];

const BASE_WEATHER = [
  { name: "Clear", value: 42, color: "#f59e0b" },
  { name: "Rainy", value: 31, color: "#3b82f6" },
  { name: "Foggy", value: 16, color: "#8b5cf6" },
  { name: "Windy", value: 7, color: "#10b981" },
  { name: "Snowy", value: 4, color: "#e2e8f0" },
];

const BASE_VEHICLE = [
  { vehicle: "Car", accidents: 1124, risk: "Medium" },
  { vehicle: "Motorcycle", accidents: 876, risk: "High" },
  { vehicle: "Truck", accidents: 543, risk: "High" },
  { vehicle: "Bus", accidents: 312, risk: "Medium" },
  { vehicle: "Auto-Rickshaw", accidents: 287, risk: "Medium" },
  { vehicle: "Bicycle", accidents: 198, risk: "Low" },
];

const BASE_DRIVER_AGE = [
  { age: "16-25", accidents: 892, percentage: 26 },
  { age: "26-35", accidents: 1124, percentage: 33 },
  { age: "36-45", accidents: 743, percentage: 22 },
  { age: "46-55", accidents: 412, percentage: 12 },
  { age: "56-65", accidents: 198, percentage: 6 },
  { age: "65+", accidents: 68, percentage: 2 },
];

const BASE_TIME = [
  { hour: "00-02", accidents: 87 }, { hour: "02-04", accidents: 64 },
  { hour: "04-06", accidents: 98 }, { hour: "06-08", accidents: 312 },
  { hour: "08-10", accidents: 287 }, { hour: "10-12", accidents: 198 },
  { hour: "12-14", accidents: 224 }, { hour: "14-16", accidents: 243 },
  { hour: "16-18", accidents: 389 }, { hour: "18-20", accidents: 412 },
  { hour: "20-22", accidents: 298 }, { hour: "22-24", accidents: 187 },
];

const BASE_RADAR = [
  { factor: "Speed", value: 87 },
  { factor: "Weather", value: 64 },
  { factor: "Driver Fatigue", value: 79 },
  { factor: "Road Condition", value: 58 },
  { factor: "Visibility", value: 72 },
  { factor: "Vehicle Fault", value: 45 },
];

// Year scale multipliers
const YEAR_SCALE = { "2023": 0.82, "2024": 1.0, "2025": 1.13 };
// Weather effect on monthly & location data
const WEATHER_M = { All: 1, Clear: 0.85, Rainy: 1.22, Foggy: 1.38 };
const WEATHER_L = { All: 1, Clear: 0.78, Rainy: 1.30, Foggy: 1.45 };

const INSIGHTS_ALL = [
  { icon: "🌙", title: "Night Risk", text: "Night driving accounts for 38% of fatal accidents despite only 22% of total traffic volume.", severity: "high", tags: ["night", "fatal", "driving", "dark"] },
  { icon: "🌧️", title: "Rain Effect", text: "Rainy conditions increase accident probability by 3.2× compared to clear weather.", severity: "high", tags: ["rain", "rainy", "weather", "probability", "wet"] },
  { icon: "🚗", title: "Speed Factor", text: "Over-speeding is the primary cause in 87% of highway fatalities.", severity: "high", tags: ["speed", "highway", "fatal", "overspeed"] },
  { icon: "👤", title: "Young Drivers", text: "Drivers aged 16-25 have 2.4× higher accident rate than the 36-45 age group.", severity: "medium", tags: ["young", "driver", "age", "16", "25"] },
  { icon: "🛣️", title: "Highway Hotspot", text: "NH-8 corridor alone contributes 18% of all recorded accidents in the dataset.", severity: "medium", tags: ["highway", "nh-8", "hotspot", "location", "road"] },
  { icon: "🌫️", title: "Fog Danger", text: "Foggy conditions lead to 4.1× higher fatality rate due to multi-vehicle pile-ups.", severity: "high", tags: ["fog", "foggy", "fatality", "visibility", "weather"] },
];

const RECOMMENDATIONS = [
  { icon: "💡", title: "Road Lighting", desc: "Install LED lighting on NH-8 and Ring Road to reduce night accidents by an estimated 40%.", priority: "Critical" },
  { icon: "📷", title: "Speed Cameras", desc: "Deploy automated speed enforcement at the top 5 hotspot locations.", priority: "Critical" },
