function DashboardPage({ monthly, location, weatherData }) {
  const totalAcc = monthly.reduce((s, d) => s + d.accidents, 0);
  const totalDead = monthly.reduce((s, d) => s + d.deaths, 0);
  const totalInj = monthly.reduce((s, d) => s + d.injuries, 0);
  const fatRate = ((totalDead / totalAcc) * 100).toFixed(1);

  return (
    <div>
      <div style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 28, fontWeight: 800, color: C.textPrimary, letterSpacing: -0.5 }}>Accident Analytics Dashboard</div>
        <div style={{ color: C.textSecondary, marginTop: 4, fontSize: 14 }}>Comprehensive road safety intelligence • Live filtered view</div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(185px,1fr))", gap: 16, marginBottom: 24 }}>
        <StatCard label="Total Accidents" value={totalAcc.toLocaleString()} sub="All locations" color={C.accent} icon="⚠️" />
        <StatCard label="Total Deaths" value={totalDead.toLocaleString()} sub="Fatal outcomes" color={C.red} icon="💔" />
        <StatCard label="Total Injuries" value={totalInj.toLocaleString()} sub="Non-fatal" color={C.yellow} icon="🏥" />
        <StatCard label="Fatality Rate" value={`${fatRate}%`} sub="Deaths/accident" color={C.purple} icon="📊" />
        <StatCard label="Night vs Day" value="38% / 62%" sub="Night risk higher" color={C.blue} icon="🌙" />
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 16, marginBottom: 16 }}>
        <ChartCard title="📈 Monthly Accident Trend">
          <ResponsiveContainer width="100%" height={260}>
            <AreaChart data={monthly}>
              <defs>
                <linearGradient id="ag" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={C.accent} stopOpacity={0.3} />
                  <stop offset="95%" stopColor={C.accent} stopOpacity={0} />
                </linearGradient>
                <linearGradient id="dg" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={C.red} stopOpacity={0.3} />
                  <stop offset="95%" stopColor={C.red} stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
              <XAxis dataKey="month" stroke={C.textMuted} tick={{ fill: C.textSecondary, fontSize: 12 }} />
              <YAxis stroke={C.textMuted} tick={{ fill: C.textSecondary, fontSize: 12 }} />
              <Tooltip content={<TT />} />
              <Legend wrapperStyle={{ color: C.textSecondary, fontSize: 13 }} />
              <Area type="monotone" dataKey="accidents" stroke={C.accent} fill="url(#ag)" strokeWidth={2} name="Accidents" />
              <Area type="monotone" dataKey="injuries" stroke={C.blue} fill="none" strokeWidth={2} strokeDasharray="4 4" name="Injuries" />
              <Area type="monotone" dataKey="deaths" stroke={C.red} fill="url(#dg)" strokeWidth={2} name="Deaths" />
            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="🌤 Accidents by Weather">
          <ResponsiveContainer width="100%" height={260}>
            <PieChart>
              <Pie data={weatherData} cx="50%" cy="50%" innerRadius={65} outerRadius={100} dataKey="value" nameKey="name" paddingAngle={3}>
                {weatherData.map((e, i) => <Cell key={i} fill={e.color} />)}
              </Pie>
              <Tooltip formatter={v => `${v}%`} contentStyle={{ background: "#1e293b", border: `1px solid ${C.border}`, borderRadius: 10, fontSize: 13 }} />
              <Legend wrapperStyle={{ color: C.textSecondary, fontSize: 12 }} />
            </PieChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
        <ChartCard title="📍 Top Hotspot Locations">
          <ResponsiveContainer width="100%" height={240}>
            <BarChart data={location.slice(0, 5)} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
              <XAxis type="number" stroke={C.textMuted} tick={{ fill: C.textSecondary, fontSize: 11 }} />
              <YAxis dataKey="location" type="category" width={110} tick={{ fill: C.textSecondary, fontSize: 11 }} />
              <Tooltip content={<TT />} />
              <Bar dataKey="accidents" fill={C.accent} radius={[0, 6, 6, 0]} name="Accidents" />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="🎯 Risk Factor Radar">
          <ResponsiveContainer width="100%" height={240}>
            <RadarChart data={BASE_RADAR} cx="50%" cy="50%" outerRadius={90}>
              <PolarGrid stroke={C.border} />
