function TimePage({ monthly }) {
  const totalScale = monthly.reduce((s, d) => s + d.accidents, 0) / BASE_MONTHLY.reduce((s, d) => s + d.accidents, 0);
  const timeScaled = BASE_TIME.map(d => ({ ...d, accidents: sc(d.accidents, totalScale) }));
  const night = timeScaled.filter(d => ["20-22", "22-24", "00-02", "02-04"].includes(d.hour)).reduce((s, d) => s + d.accidents, 0);
  const day = timeScaled.reduce((s, d) => s + d.accidents, 0) - night;
  return (
    <div>
      <PageHeader title="🕐 Time Analysis" sub="Hourly distribution and day vs night risk assessment" />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
        <StatCard label="Day Accidents" value={day.toLocaleString()} sub="06:00 – 20:00" color={C.yellow} icon="☀️" />
        <StatCard label="Night Accidents" value={night.toLocaleString()} sub="20:00 – 06:00" color={C.blue} icon="🌙" />
      </div>
      <ChartCard title="Accidents by Hour of Day">
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={timeScaled}>
            <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
            <XAxis dataKey="hour" tick={{ fill: C.textSecondary, fontSize: 12 }} />
            <YAxis tick={{ fill: C.textSecondary, fontSize: 12 }} />
            <Tooltip content={<TT />} />
            <Bar dataKey="accidents" name="Accidents" radius={[6, 6, 0, 0]}>
              {timeScaled.map((d, i) => {
                const h = parseInt(d.hour);
                return <Cell key={i} fill={h >= 20 || h < 6 ? C.blue : C.accent} />;
              })}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
        <div style={{ display: "flex", gap: 20, marginTop: 12 }}>
          {[[`☀️ Day (06:00–20:00)`, C.accent], [`🌙 Night (20:00–06:00)`, C.blue]].map(([label, color]) => (
            <div key={label} style={{ display: "flex", alignItems: "center", gap: 8, color: C.textSecondary, fontSize: 13 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, background: color }} />{label}
            </div>
          ))}
        </div>
      </ChartCard>
    </div>
  );
}

