function InsightsPage({ search }) {
  const q = search.toLowerCase();
  const filtered = q
    ? INSIGHTS_ALL.filter(ins =>
      ins.title.toLowerCase().includes(q) ||
      ins.text.toLowerCase().includes(q) ||
      ins.tags.some(t => t.includes(q))
    )
    : INSIGHTS_ALL;

  return (
    <div>
      <PageHeader title="💡 Smart Insights" sub="AI-generated findings from accident pattern analysis" />
      {search && (
        <div style={{ marginBottom: 16, color: C.textSecondary, fontSize: 13 }}>
          <strong style={{ color: C.accent }}>{filtered.length}</strong> insight{filtered.length !== 1 ? "s" : ""} matching <strong style={{ color: C.accent }}>"{search}"</strong>
        </div>
      )}
      {filtered.length === 0 ? <Empty query={search} /> : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(300px,1fr))", gap: 16 }}>
          {filtered.map((ins, i) => {
            const color = ins.severity === "high" ? C.red : ins.severity === "medium" ? C.yellow : C.green;
            return (
              <div key={i} style={{ background: C.card, border: `1px solid ${color}50`, borderRadius: 16, padding: 24, borderLeft: `4px solid ${color}`, transition: "transform .2s,box-shadow .2s" }}
                onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = "0 12px 32px rgba(0,0,0,.3)"; }}
                onMouseLeave={e => { e.currentTarget.style.transform = ""; e.currentTarget.style.boxShadow = ""; }}>
                <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12 }}>
                  <div style={{ fontSize: 28 }}>{ins.icon}</div>
                  <div style={{ fontWeight: 700, color: C.textPrimary, fontSize: 16 }}>{ins.title}</div>
                  <div style={{ marginLeft: "auto", background: `${color}20`, color, padding: "3px 10px", borderRadius: 99, fontSize: 11, fontWeight: 700, textTransform: "uppercase" }}>{ins.severity}</div>
                </div>
                <div style={{ color: C.textSecondary, fontSize: 14, lineHeight: 1.6 }}>{ins.text}</div>
              </div>
            );
          })}
        </div>
      )}
      <div style={{ marginTop: 24 }}>
        <ChartCard title="Risk Factor Radar – Composite View">
          <ResponsiveContainer width="100%" height={300}>
            <RadarChart data={BASE_RADAR} cx="50%" cy="50%" outerRadius={110}>
              <PolarGrid stroke={C.border} />
              <PolarAngleAxis dataKey="factor" tick={{ fill: C.textSecondary, fontSize: 12 }} />
              <Radar name="Risk Score" dataKey="value" stroke={C.accent} fill={C.accent} fillOpacity={0.25} strokeWidth={2} />
              <Tooltip contentStyle={{ background: "#1e293b", border: `1px solid ${C.border}`, borderRadius: 10, fontSize: 13 }} />
            </RadarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>
    </div>
  );
}

function RecommendationsPage({ search }) {
  const priorityColor = { Critical: C.red, High: C.yellow, Medium: C.green };
  const q = search.toLowerCase();
  const filtered = q
    ? RECOMMENDATIONS.filter(r =>
      r.title.toLowerCase().includes(q) ||
      r.desc.toLowerCase().includes(q) ||
      r.priority.toLowerCase().includes(q)
    )
    : RECOMMENDATIONS;

  return (
    <div>
      <PageHeader title="✅ Recommendations" sub="Data-driven safety improvement strategies" />
      {search && (
        <div style={{ marginBottom: 16, color: C.textSecondary, fontSize: 13 }}>
          <strong style={{ color: C.accent }}>{filtered.length}</strong> recommendation{filtered.length !== 1 ? "s" : ""} matching <strong style={{ color: C.accent }}>"{search}"</strong>
        </div>
      )}
      {filtered.length === 0 ? <Empty query={search} /> : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(300px,1fr))", gap: 16 }}>
          {filtered.map((r, i) => {
            const color = priorityColor[r.priority];
            return (
              <div key={i} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 16, padding: 24, position: "relative", overflow: "hidden", transition: "transform .2s,border-color .2s" }}
                onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.borderColor = color; }}
                onMouseLeave={e => { e.currentTarget.style.transform = ""; e.currentTarget.style.borderColor = C.border; }}>
                <div style={{ position: "absolute", top: 16, right: 16, background: `${color}20`, color, padding: "3px 12px", borderRadius: 99, fontSize: 11, fontWeight: 700 }}>{r.priority}</div>
                <div style={{ fontSize: 32, marginBottom: 12 }}>{r.icon}</div>
                <div style={{ fontWeight: 700, color: C.textPrimary, fontSize: 16, marginBottom: 10 }}>{r.title}</div>
                <div style={{ color: C.textSecondary, fontSize: 14, lineHeight: 1.6 }}>{r.desc}</div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─── ROOT ─────────────────────────────────────────────────────────────────────
export default function App() {
  const [activePage, setActivePage] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [year, setYear] = useState("2024");
  const [weather, setWeather] = useState("All");
  const [search, setSearch] = useState("");
  const [uploadMsg, setUploadMsg] = useState("");

  // ── Compute filtered data whenever year / weather changes ─────────────────
  const ys = YEAR_SCALE[year] ?? 1;
  const mf = WEATHER_M[weather] ?? 1;
  const lf = WEATHER_L[weather] ?? 1;
  const df = weather === "Foggy" ? 1.3 : weather === "Rainy" ? 1.15 : 1;

  const filteredMonthly = useMemo(() =>
    BASE_MONTHLY.map(d => ({
      month: d.month,
      accidents: sc(d.accidents, ys * mf),
      deaths: sc(d.deaths, ys * mf * df),
      injuries: sc(d.injuries, ys * mf),
    }))
    , [year, weather]);

  const filteredLocation = useMemo(() => {
    const q = search.toLowerCase();
    return BASE_LOCATION
      .map(d => ({
        location: d.location,
        accidents: sc(d.accidents, ys * lf),
        injuries: sc(d.injuries, ys * lf),
        deaths: sc(d.deaths, ys * lf * df),
      }))
      .filter(d => !q || d.location.toLowerCase().includes(q));
  }, [year, weather, search]);

  const filteredWeather = useMemo(() => {
    if (weather === "All") return BASE_WEATHER;
    return BASE_WEATHER.map(w => ({
      ...w,
      value: w.name === weather
        ? Math.min(99, w.value + 20)
        : Math.max(1, w.value - 6),
    }));
  }, [weather]);

  const filteredVehicle = useMemo(() => BASE_VEHICLE.map(d => ({ ...d, accidents: sc(d.accidents, ys * mf) })), [year, weather]);
  const filteredDriverAge = useMemo(() => BASE_DRIVER_AGE.map(d => ({ ...d, accidents: sc(d.accidents, ys) })), [year]);

  const filterLabel = [
    year !== "2024" && `Year: ${year}`,
    weather !== "All" && `Weather: ${weather}`,
    search && `Search: "${search}"`,
  ].filter(Boolean).join("  •  ");

  const handleUpload = e => {
    const file = e.target.files[0];
    if (file) setUploadMsg(`✅ "${file.name}" loaded — dataset applied.`);
